// Extract text content from the uploaded PDF binary data
const items = $input.all();
const results = [];

for (const item of items) {
  const binaryData = item.binary;
  let extractedText = '';

  if (binaryData && binaryData.data) {
    // Get the base64 PDF content
    const pdfBase64 = binaryData.data.data;
    // Basic text extraction from PDF binary
    const buffer = Buffer.from(pdfBase64, 'base64');
    const content = buffer.toString('utf8');

    // Extract readable text between stream markers
    const textMatches = content.match(/\((.*?)\)/g);
    if (textMatches) {
      extractedText = textMatches
        .map(m => m.slice(1, -1))
        .filter(t => t.length > 2)
        .join(' ');
    }

    if (!extractedText || extractedText.length < 50) {
      extractedText = 'PDF text extraction returned minimal content. The AI will work with available data.';
    }
  }

  results.push({
    json: {
      contractText: extractedText,
      contractType: item.json['Contract Type'] || 'Unknown',
      notes: item.json['Notes'] || '',
      uploadedAt: new Date().toISOString()
    }
  });
}

return results;

// Parse the AI response and structure the risk analysis
const items = $input.all();
const results = [];

for (const item of items) {
  const aiResponse = item.json.text || item.json.response || '';
  let analysis;

  try {
    // Try to extract JSON from the response
    const jsonMatch = aiResponse.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      analysis = JSON.parse(jsonMatch[0]);
    } else {
      analysis = {
        overallRiskScore: 5,
        summary: aiResponse.substring(0, 200),
        riskyClause: [],
        missingProtections: [],
        favorabilityScore: 5
      };
    }
  } catch (e) {
    analysis = {
      overallRiskScore: 5,
      summary: 'Could not parse structured response. Raw: ' + aiResponse.substring(0, 300),
      riskyClause: [],
      missingProtections: [],
      favorabilityScore: 5
    };
  }

  const highRiskClauses = (analysis.riskyClause || []).filter(c => c.severity === 'high');

  results.push({
    json: {
      ...analysis,
      highRiskCount: highRiskClauses.length,
      totalRisks: (analysis.riskyClause || []).length,
      isHighRisk: analysis.overallRiskScore > 7,
      reviewedAt: new Date().toISOString(),
      contractType: items[0].json.contractType || 'Unknown'
    }
  });
}

return results;

